import { Test, TestingModule } from '@nestjs/testing';
import { PrismaService } from './../../../../libs/database';
import { NotFoundException } from '@nestjs/common';
import { SignOutService } from '../../services/sign-out.service';
import { UsersService } from './../../../../modules/users/users.service';

describe('SignOutService - Integration', () => {
  let service: SignOutService;
  let prisma: PrismaService;
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  let usersService: UsersService;

  beforeAll(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [SignOutService, UsersService, PrismaService],
    }).compile();

    service = module.get<SignOutService>(SignOutService);
    prisma = module.get<PrismaService>(PrismaService);
    usersService = module.get<UsersService>(UsersService);

    await prisma.user.deleteMany();
  });

  afterAll(async () => {
    await prisma.$disconnect();
  });

  it('should sign out successfully', async () => {
    const user = await prisma.user.create({
      data: {
        firstname: 'Test',
        lastname: 'User',
        nickname: 'testuser',
        email: 'test@example.com',
        password: 'hashed-password',
        role: 'USER',
        refreshToken: 'some-token',
      },
    });

    await service.execute(user.id);

    const updatedUser = await prisma.user.findUnique({
      where: { id: user.id },
    });

    expect(updatedUser!.refreshToken).toBeNull();
  });

  it('should throw NotFoundException if user does not exist', async () => {
    await expect(service.execute(99999)).rejects.toThrow(NotFoundException);
  });
});
